// Route by email type based on subject line
//
// Email types:
//   1. New booking:    "Booking - S709718 - GYG7VK4GF7MB"
//   2. Urgent booking: "Urgent: New booking received - S709718 - GYG7VK4GF7MB"
//   3. Cancellation:   "A booking has been canceled - S709718 - GYG7VK4GF7MB"

const subject = ($json.subject || '').trim();

let emailType = 'unknown';

if (subject.toLowerCase().includes('canceled')) {
  emailType = 'cancellation';
} else if (subject.startsWith('Booking -') || subject.startsWith('Urgent:')) {
  emailType = 'new_booking';
}

// Extract reference code from subject (always the last segment after " - ")
const subjectParts = subject.split(' - ');
const referenceCode = (subjectParts[subjectParts.length - 1] || '').trim();

return {
  json: {
    ...($json),
    email_type: emailType,
    reference_code: referenceCode
  }
};

// Parse the GetYourGuide booking confirmation HTML email body
// Handles both regular and urgent booking emails (same HTML body format).
//
// Subject formats:
//   Regular: "Booking - S709718 - GYG7VK4GF7MB"
//   Urgent:  "Urgent: New booking received - S709718 - GYG7VK4GF7MB"
//
// HTML body contains structured data with labels and <strong> values.
//
// Fields to extract:
//   - reference_code (already extracted by Route by Type)
//   - activity_name (from element with class containing "activity-title")
//   - event_date / event_time (from "Date" label, e.g. "February 20, 2026 7:00 PM")
//   - ticket_count (from "Number of participants", e.g. "2 x Adults (Age 0 - 99)")
//   - customer_name -> first_name, last_name (from "Main customer" label)
//   - customer_email (mailto: link near customer name)
//   - customer_phone ("Phone: +61478009744")
//   - gross_revenue (from "Price" label, e.g. "A$ 70.00")

const subject = $json.subject || '';
const html = $json.html || $json.textHtml || $json.body || '';
const referenceCode = $json.reference_code || '';

// --- Activity name ---
let activityName = '';
const activityTitleMatch = html.match(/class\s*=\s*"[^"]*activity-title[^"]*"[^>]*>([^<]+)/i);
if (activityTitleMatch) {
  activityName = activityTitleMatch[1].trim();
} else {
  const fallbackMatch = html.match(/activity-title[^>]*>\s*([^<]+)/i);
  if (fallbackMatch) {
    activityName = fallbackMatch[1].trim();
  }
}

// --- Date and Time ---
let eventDate = '';
let eventTime = '';
const dateBlockMatch = html.match(/Date\s*(?:<[^>]*>\s*)*<strong>([^<]+)<\/strong>/i);
if (dateBlockMatch) {
  const rawDate = dateBlockMatch[1].trim();

  const months = {
    'january': '01', 'february': '02', 'march': '03', 'april': '04',
    'may': '05', 'june': '06', 'july': '07', 'august': '08',
    'september': '09', 'october': '10', 'november': '11', 'december': '12'
  };

  // Try with time: "February 20, 2026 7:00 PM"
  const withTimeMatch = rawDate.match(/^(\w+)\s+(\d{1,2}),?\s+(\d{4})\s+(\d{1,2}:\d{2})\s*(AM|PM)$/i);
  // Try without time: "February 18, 2026"
  const noTimeMatch = rawDate.match(/^(\w+)\s+(\d{1,2}),?\s+(\d{4})$/);

  if (withTimeMatch) {
    const monthName = withTimeMatch[1].toLowerCase();
    const day = withTimeMatch[2].padStart(2, '0');
    const year = withTimeMatch[3];
    const month = months[monthName] || '01';
    eventDate = `${year}-${month}-${day}`;

    let hours = parseInt(withTimeMatch[4].split(':')[0], 10);
    const minutes = withTimeMatch[4].split(':')[1];
    const ampm = withTimeMatch[5].toUpperCase();
    if (ampm === 'PM' && hours !== 12) hours += 12;
    if (ampm === 'AM' && hours === 12) hours = 0;
    eventTime = `${hours.toString().padStart(2, '0')}:${minutes}:00`;
  } else if (noTimeMatch) {
    const monthName = noTimeMatch[1].toLowerCase();
    const day = noTimeMatch[2].padStart(2, '0');
    const year = noTimeMatch[3];
    const month = months[monthName] || '01';
    eventDate = `${year}-${month}-${day}`;
  }
}

// --- Number of participants ---
let ticketCount = 1;
const participantsMatch = html.match(/Number of participants\s*(?:<[^>]*>\s*)*(?:<[^>]*>)*(\d+)\s*x/i);
if (participantsMatch) {
  ticketCount = parseInt(participantsMatch[1], 10);
} else {
  const altMatch = html.match(/<strong>\s*(\d+)\s*x\s*<\/strong>/i);
  if (altMatch) {
    ticketCount = parseInt(altMatch[1], 10);
  }
}

// --- Customer name ---
let firstName = '';
let lastName = '';
const customerMatch = html.match(/Main customer\s*(?:<[^>]*>\s*)*([A-Z][a-zA-Z'-]+(?:\s+[A-Z][a-zA-Z'-]+)+)/i);
if (customerMatch) {
  const fullName = customerMatch[1].trim();
  const nameParts = fullName.split(/\s+/);
  firstName = nameParts[0] || '';
  lastName = nameParts.slice(1).join(' ') || '';
} else {
  const altCustomerMatch = html.match(/Main customer\s*(?:<[^>]*>\s*)*<strong>([^<]+)<\/strong>/i);
  if (altCustomerMatch) {
    const fullName = altCustomerMatch[1].trim();
    const nameParts = fullName.split(/\s+/);
    firstName = nameParts[0] || '';
    lastName = nameParts.slice(1).join(' ') || '';
  }
}

// --- Customer email ---
let customerEmail = '';
const emailMatch = html.match(/mailto:([^"'\s>]+@[^"'\s>]+getyourguide[^"'\s>]*)/i);
if (emailMatch) {
  customerEmail = emailMatch[1].trim().toLowerCase();
} else {
  const altEmailMatch = html.match(/Main customer[\s\S]{0,500}?mailto:([^"'\s>]+)/i);
  if (altEmailMatch) {
    customerEmail = altEmailMatch[1].trim().toLowerCase();
  }
}

// --- Customer phone ---
let customerPhone = '';
const phoneMatch = html.match(/Phone:\s*([+\d][\d\s-]+)/i);
if (phoneMatch) {
  customerPhone = phoneMatch[1].trim();
}

// --- Price / gross revenue ---
let grossRevenue = 0;
const priceMatch = html.match(/Price\s*(?:<[^>]*>\s*)*(?:[A-Z]{1,3}\$?)\s*([\d,.]+)/i);
if (priceMatch) {
  grossRevenue = parseFloat(priceMatch[1].replace(/,/g, ''));
} else {
  const altPriceMatch = html.match(/A\$\s*([\d,.]+)/i);
  if (altPriceMatch) {
    grossRevenue = parseFloat(altPriceMatch[1].replace(/,/g, ''));
  }
}
if (isNaN(grossRevenue)) grossRevenue = 0;

return {
  json: {
    reference_code: referenceCode,
    activity_name: activityName,
    event_date: eventDate,
    event_time: eventTime,
    ticket_count: isNaN(ticketCount) ? 1 : ticketCount,
    first_name: firstName,
    last_name: lastName,
    customer_email: customerEmail,
    customer_phone: customerPhone,
    gross_revenue: grossRevenue,
    source_email_subject: subject,
    source_email_date: $json.date || ''
  }
};

// Merge the parsed GYG booking data with the matched event/session
const booking = $('Parse GYG Email Body').item.json;
const matchResult = $input.item.json;

// The RPC returns an array - take the first match
const match = Array.isArray(matchResult) ? matchResult[0] : matchResult;

if (!match || !match.event_id) {
  return {
    json: {
      ...booking,
      event_id: null,
      session_id: null,
      match_status: 'no_match',
      match_message: `No event found matching: ${booking.activity_name} on ${booking.event_date}`
    }
  };
}

return {
  json: {
    ...booking,
    event_id: match.event_id,
    session_id: match.session_id || null,
    match_status: 'matched',
    match_message: `Matched to event: ${match.event_name || match.event_id}`
  }
};

// Prepare the final payload for manual_ticket_entries
const booking = $('Merge Match Data').item.json;
const customerResult = $input.item.json;

// Get customer_id from upsert result
const customer = Array.isArray(customerResult) ? customerResult[0] : customerResult;
const customerId = customer?.id || null;

// GetYourGuide Partner ID
const GYG_PARTNER_ID = '237e9e0e-846c-4004-b883-1348264bd007';

// Commission rate: 27%
const COMMISSION_RATE = 27;

return {
  json: {
    event_id: booking.event_id,
    session_id: booking.session_id,
    partner_id: GYG_PARTNER_ID,
    ticket_count: booking.ticket_count,
    gross_revenue: booking.gross_revenue,
    commission_rate: COMMISSION_RATE,
    entry_date: booking.event_date || new Date().toISOString().split('T')[0],
    first_name: booking.first_name,
    last_name: booking.last_name,
    email: booking.customer_email,
    booking_reference: booking.reference_code,
    customer_id: customerId,
    source: 'n8n',
    status: 'confirmed',
    notes: `GYG import: ${booking.activity_name}`,
    reference_id: booking.reference_code
  }
};

// Parse the GetYourGuide cancellation email body
// Subject format: "A booking has been canceled - S709718 - GYGMX4Q2LAZW"
//
// The cancellation email has a simpler body with <strong> labels:
//   <strong>Reference Number:</strong> GYGMX4Q2LAZW
//   <strong>Name:</strong> Aaron Lee
//   <strong>Date:</strong> February 14, 2026 7:00 PM
//   <strong>Tour:</strong> Comedy Show - iD Comedy Club Sydney - Friday / Saturday

const subject = $json.subject || '';
const html = $json.html || $json.textHtml || $json.body || '';
const referenceCode = $json.reference_code || '';

// --- Reference Number from body (as verification) ---
let bodyReference = '';
const refMatch = html.match(/<strong>\s*Reference Number:\s*<\/strong>\s*([A-Z0-9]+)/i);
if (refMatch) {
  bodyReference = refMatch[1].trim();
}

// --- Customer Name ---
let customerName = '';
const nameMatch = html.match(/<strong>\s*Name:\s*<\/strong>\s*([^<]+)/i);
if (nameMatch) {
  customerName = nameMatch[1].trim();
}

// --- Date ---
let cancelledEventDate = '';
const dateMatch = html.match(/<strong>\s*Date:\s*<\/strong>\s*([^<]+)/i);
if (dateMatch) {
  cancelledEventDate = dateMatch[1].trim();
}

// --- Tour ---
let tourName = '';
const tourMatch = html.match(/<strong>\s*Tour:\s*<\/strong>\s*([^<]+)/i);
if (tourMatch) {
  tourName = tourMatch[1].trim();
}

// Use the body reference if available, otherwise fall back to subject reference
const finalReference = bodyReference || referenceCode;

return {
  json: {
    reference_code: finalReference,
    customer_name: customerName,
    cancelled_event_date: cancelledEventDate,
    tour_name: tourName,
    source_email_subject: subject,
    source_email_date: $json.date || ''
  }
};

// Handle results from both new booking inserts and cancellation updates
// This node receives items from both the Insert Ticket Entry and Cancel Ticket Entry paths.
const items = $input.all();
let inserted = 0;
let cancelled = 0;
let duplicates = 0;
let errors = 0;
const details = [];

for (const item of items) {
  const statusCode = item.json.statusCode || item.json?.headers?.status;
  const body = item.json.body || item.json;

  if (statusCode === 201) {
    // New booking inserted successfully
    inserted++;
    const entry = Array.isArray(body) ? body[0] : body;
    details.push({ action: 'inserted', reference: entry?.booking_reference || 'unknown' });
  } else if (statusCode === 200) {
    // Cancellation PATCH successful (or other 200)
    const entry = Array.isArray(body) ? body[0] : body;
    if (entry?.status === 'cancelled') {
      cancelled++;
      details.push({ action: 'cancelled', reference: entry?.booking_reference || 'unknown' });
    } else {
      inserted++;
      details.push({ action: 'updated', reference: entry?.booking_reference || 'unknown' });
    }
  } else if (statusCode === 409) {
    duplicates++;
    details.push({ action: 'duplicate_skipped', statusCode });
  } else {
    errors++;
    details.push({ action: 'error', statusCode, body: JSON.stringify(body).substring(0, 200) });
  }
}

return {
  json: {
    summary: 'GetYourGuide Import Complete',
    inserted,
    cancelled,
    duplicates_skipped: duplicates,
    errors,
    total_processed: items.length,
    details,
    timestamp: new Date().toISOString()
  }
};
